+%% fixture_id: requirement_edge_case
+%% purpose: edge cases for requirementDiagram parsing and layout
+requirementDiagram
+  requirement empty_req {
+    id: REQ-EMPTY
+  }
+  requirement long_name_requirement_that_exceeds_normal_box_width {
+    id: REQ-LONG
+    text: This requirement has a very long description text that should exercise label truncation and wrapping in the entity box renderer
+    risk: low
+    verifymethod: demonstration
+  }
+  functionalRequirement func_req {
+    id: FR-001
+    text: Functional requirement type
+    risk: medium
+    verifymethod: test
+  }
+  performanceRequirement perf_req {
+    id: PR-001
+    text: Performance requirement type
+    risk: high
+    verifymethod: analysis
+  }
+  interfaceRequirement iface_req {
+    id: IR-001
+    text: Interface requirement type
+    risk: low
+    verifymethod: inspection
+  }
+  element standalone_element {
+    type: device
+  }
+  element connected_element {
+    type: service
+    docref: https://example.com/spec
+  }
+  connected_element - satisfies -> func_req
+  connected_element - derives -> perf_req
+  func_req - traces -> iface_req
+  perf_req - refines -> long_name_requirement_that_exceeds_normal_box_width
+  standalone_element - contains -> empty_req
